mapper.select:
SELECT sensor_id AS sensorId, device_no AS deviceNo, fiber_no AS fiberNo,
       raw_value AS rawValue, wavelength AS wavelength, wavelength_shift AS wavelengthShift,
       intensity AS intensity, collect_time AS collectTime
FROM fiber_raw_data
WHERE sensor_id = #{sensorId} AND deleted = 0
AND collect_time >= #{startTime}
AND collect_time <= #{endTime}
ORDER BY collect_time ASC
LIMIT #{limit}
